SELECT COUNT(1)
FROM settlement_request_header
WHERE company = #{company}
  AND store = #{store}
  AND settlement_type = #{settlementType}
  AND reference_no = #{referenceNo}
  AND status <> 'SETTLED'

SELECT COUNT(1)
FROM settlement_request_detail
WHERE settlement_id = #{settlementId}
  AND document_type = #{documentType}
  AND document_no = #{documentNo}
  AND item_code = #{itemCode}
